var offerSiteId = 4170;
 function asd() {
 var display = document.getElementById("addmoresite");
 var addmorebutton = document.getElementById("addmorebutton");
 display.style.display = 'inline';
 addmorebutton.style.display = 'none';
 }
 $().ready(function () {
 $('#offerSiteLink').on('click', function () {
 asd();
 });
 });

 $(document).ready(function () {
 var isFavorite = !false;
 $('.fav_4170').on('click', function () {
 var isAuthenticated = false;
 var isCompany = true;
 if (isAuthenticated === false) {
 $('#favoriteModal').modal('show');
 }
 else if (isCompany === true) {
 $('#companyModal').modal('show');
 }
 else {
 isFavorite = !isFavorite;
 $.ajax({
 url: '/Offer/SwitchFavoriteStatus',
 type: 'POST',
 contentType: 'application/json',
 data: JSON.stringify({ offersiteId: 4170 }),
 success: function (response) {
 if (response.success) {
 updateFavoriteDesign($('.fav_4170'), isFavorite);
 } else {
 alert('Hiba a kedvencekhez adás közben');
 }
 },
 error: function () {
 alert('Hiba');
 }
 });
 }
 });
 });

 var heartActiveIconSrc = "~/Frontend/Images/Icons/offer-card-heart-active.svg";

 function updateFavoriteDesign(div, isFavorite) {
 if (isFavorite) {
 div.html(`
 `);
 } else {
 div.html(`
 `);
 }
 }
 


 

